noncompliant:
// Noncompliant: Jumping into a block
void badFunction() {
    if (condition) {
        goto label_inside; // Jump into block
    }

    for (int i = 0; i < 10; i++) {
label_inside: // Label inside for loop
        printf("Inside loop");
    }
}

compliant:
// Compliant: Structured control flow without jumping into blocks
void goodFunction() {
    if (condition) {
        for (int i = 0; i < 10; i++) {
            printf("Inside loop");
        }
    } else {
        for (int i = 0; i < 10; i++) {
            printf("Inside loop");
        }
    }
}
